  const [reportType, setReportType] = useState('Laporan Bulanan');
  const [studentId, setStudentId] = useState('');
  const [academicYear, setAcademicYear] = useState('2025/2026');
  const [month, setMonth] = useState('Desember');

  const [klasikalTahfizh, setKlasikalTahfizh] = useState({ from: { surah: '', ayah: '' as any }, to: { surah: '', ayah: '' as any } });
  const [klasikalTilawah, setKlasikalTilawah] = useState<any>({ type: 'quran', from: { surah: '', ayah: '', jilid: '', halaman: '' }, to: { surah: '', ayah: '', jilid: '', halaman: '' } });

  const [attendance, setAttendance] = useState<number>(100);
  const [behaviorScore, setBehaviorScore] = useState<number>(10);
  const [tilawahMethod, setTilawahMethod] = useState<'Al-Quran' | 'Iqra'>('Al-Quran');
  const [tilawahFromSurah, setTilawahFromSurah] = useState(''); 
  const [tilawahFromVerse, setTilawahFromVerse] = useState<number | string>(''); 
  const [tilawahToSurah, setTilawahToSurah] = useState('');
  const [tilawahToVerse, setTilawahToVerse] = useState<number | string>(''); 

  const [tahfizhFromSurah, setTahfizhFromSurah] = useState(''); 
  const [tahfizhFromVerse, setTahfizhFromVerse] = useState<number | string>(''); 
  const [tahfizhToSurah, setTahfizhToSurah] = useState('');
  const [tahfizhToVerse, setTahfizhToVerse] = useState<number | string>(''); 

  const [baselineJuz, setBaselineJuz] = useState<number | string>(0);
  const [baselinePages, setBaselinePages] = useState<number | string>(0);
  const [baselineLines, setBaselineLines] = useState<number | string>(0);
  const [notes, setNotes] = useState('');

  const safeNum = (val: any) => (val === '' ? 0 : Number(val));

  useEffect(() => {
    if (!teacherId) return;
    getStudentsByTeacher(teacherId).then(data => { setStudents(data); setIsLoading(false); });
  }, [teacherId]);

  const handleSave = async () => {
    if (!studentId) return alert("Pilih siswa.");
    const selectedStudent = students.find(s => s.id === studentId);
    if (!selectedStudent) return;

    setIsSaving(true);
    try {
      // 1. Hitung Hasil Tahfizh
      const tfRes = SDQQuranEngine.calculate(tahfizhFromSurah, safeNum(tahfizhFromVerse), tahfizhToSurah, safeNum(tahfizhToVerse));
      const tfResultStr = tfRes.valid ? `${tfRes.pages}H ${tfRes.lines}B` : "-";

      // 2. Hitung Hasil Tilawah
      let tlResultStr = "-";
      if (tilawahMethod === 'Al-Quran') {
        const tlRes = SDQQuranEngine.calculate(tilawahFromSurah, safeNum(tilawahFromVerse), tilawahToSurah, safeNum(tilawahToVerse));
        tlResultStr = tlRes.valid ? `${tlRes.pages}H ${tlRes.lines}B` : "-";
      } else {
        const tlRes = SDQQuranEngine.calculate(tilawahFromSurah, safeNum(tilawahFromVerse), tilawahToSurah, safeNum(tilawahToVerse));
        tlResultStr = tlRes.valid ? `${tlRes.pages} Hal` : "-";
      }

      const fmt = (s: string, v: any) => (s ? `${s}: ${v === '' ? '-' : v}` : '-');
      const makeRange = (fs: string, fv: any, ts: string, tv: any) => (!fs && !ts ? '-' : `${fmt(fs, fv)} - ${fmt(ts, tv)}`);

      await saveSDQReport({
        studentId, studentName: selectedStudent.name, teacherId: teacherId || '', className: selectedStudent.className, 
        type: reportType, month, academicYear, date: new Date().toISOString().split('T')[0], evaluation: '',
        attendance, behaviorScore,
        tilawah: { 
          method: tilawahMethod, 
          individual: makeRange(tilawahFromSurah, tilawahFromVerse, tilawahToSurah, tilawahToVerse),
          result: tlResultStr 
        },
        tahfizh: { 
          individual: makeRange(tahfizhFromSurah, tahfizhFromVerse, tahfizhToSurah, tahfizhToVerse),
          result: tfResultStr 
        },
        totalHafalan: { juz: safeNum(baselineJuz), pages: safeNum(baselinePages), lines: safeNum(baselineLines) },
        notes
      });

      alert("Laporan berhasil disimpan!");
      navigate('/guru/view-report');
    } catch (e) { alert("Gagal."); } finally { setIsSaving(false); }
  };

