import React, { useState } from 'react';
import { HashRouter, Switch, Route, Redirect } from 'react-router-dom';
import { Layout } from './app/layout';
import LoginPage from './app/(auth)/login/page';
import CoordinatorDashboard from './app/coordinator/dashboard/page';
import CoordinatorGuruPage from './app/coordinator/guru/page';
import CoordinatorTeacherDetail from './app/coordinator/guru/[id]/page';
import CoordinatorSiswaPage from './app/coordinator/siswa/page';
import CoordinatorKelasPage from './app/coordinator/kelas/page';
import CoordinatorReportsPage from './app/coordinator/reports/page';
import CoordinatorRaporPage from './app/coordinator/rapor/page';
import CoordinatorEvaluationsPage from './app/coordinator/evaluations/page';
import GuruDashboard from './app/guru/dashboard/page';
import GuruHalaqahPage from './app/guru/halaqah/page';
import GuruLaporanPage from './app/guru/laporan/page';
import GuruViewReportPage from './app/guru/view-report/page';
import GuruEvaluationPage from './app/guru/evaluation/page';
import GuruGradesPage from './app/guru/grades/page';
import GuruRaporPage from './app/guru/rapor/page';
import { getStoredUser, simpleLogout } from './services/simpleAuth';
import { User } from './types';

function App() {
  const [user, setUser] = useState<User | null>(getStoredUser() || {
    id: 'u2',
    name: 'Ust. Hasan (Auto-Login)',
    nickname: 'Ustadz Hasan',
    email: 'guru@sdq.com',
    role: 'GURU'
  });

  const handleLogin = (newUser: User) => {
    setUser(newUser);
  };

  const handleLogout = async () => {
    try {
      await simpleLogout();
      setUser(null);
    } catch (error) {
      console.error("Gagal logout:", error);
      setUser(null);
    }
  };

  return (
    <HashRouter>
      <Switch>
        <Route path="/login">
          {!user ? <LoginPage onLogin={handleLogin} /> : <Redirect to="/" />}
        </Route>

        <Route path="/">
           <Layout user={user} onLogout={handleLogout}>
             <Switch>
                <Route exact path="/">
                  {user?.role === 'KOORDINATOR' 
                    ? <Redirect to="/coordinator/dashboard" /> 
                    : <Redirect to="/guru/dashboard" />
                  }
                </Route>

                <Route path="/coordinator/dashboard" component={CoordinatorDashboard} />
                <Route exact path="/coordinator/guru" component={CoordinatorGuruPage} />
                <Route path="/coordinator/guru/:id" component={CoordinatorTeacherDetail} />
                <Route path="/coordinator/siswa" component={CoordinatorSiswaPage} />
                <Route path="/coordinator/kelas" component={CoordinatorKelasPage} />
                <Route path="/coordinator/reports" component={CoordinatorReportsPage} />
                <Route path="/coordinator/rapor" component={CoordinatorRaporPage} />
                <Route path="/coordinator/evaluations" component={CoordinatorEvaluationsPage} />

                <Route path="/guru/dashboard">
                  <GuruDashboard teacherId={user?.id} />
                </Route>
                <Route path="/guru/halaqah">
                  <GuruHalaqahPage teacherId={user?.id} />
                </Route>
                <Route path="/guru/laporan">
                  <GuruLaporanPage teacherId={user?.id} />
                </Route>
                <Route path="/guru/view-report">
                  <GuruViewReportPage teacherId={user?.id} />
                </Route>
                <Route path="/guru/evaluation">
                  <GuruEvaluationPage teacherId={user?.id} />
                </Route>
                <Route path="/guru/grades">
                  <GuruGradesPage teacherId={user?.id} />
                </Route>
                <Route path="/guru/rapor">
                  <GuruRaporPage teacherId={user?.id} teacherName={user?.name} />
                </Route>

                <Route path="*">
                  <Redirect to="/" />
                </Route>
             </Switch>
           </Layout>
        </Route>
      </Switch>
    </HashRouter>
  );
}

export default App;

import React, { useEffect, useState } from 'react';
import { useParams, useHistory } from 'react-router-dom';
