                <th rowSpan={2} className="px-3 py-4 border-r border-white/10">KET</th>
                <th rowSpan={2} className="px-3 py-4 border-r border-white/10">CATATAN</th>
                <th rowSpan={2} className="px-3 py-4">AKSI</th>
