/**
 * FEATURE: HALAQAH REASSIGNMENT (Ganti Guru)
 * Memindahkan siswa dari guru lama ke guru baru tanpa mengubah histori laporan lama.
 */
export const reassignHalaqahTeacher = async (
  className: string, 
  oldTeacherId: string, 
  newTeacherId: string,
  newTeacherName: string,
  oldTeacherName: string,
  coordinatorId: string
): Promise<string> => {
  if (!db) throw new Error("Firestore not initialized");

  if (oldTeacherId === newTeacherId) {
    throw new Error("Guru pengganti tidak boleh sama dengan guru saat ini.");
  }

  const batch = writeBatch(db);

  // 1. Cari semua siswa di kelas tersebut yang masih dipegang guru lama
  const studentsQuery = query(
    collection(db, 'siswa'), 
    where('className', '==', className),
    where('teacherId', '==', oldTeacherId)
  );

  const studentSnap = await getDocs(studentsQuery);
  if (studentSnap.empty) {
    throw new Error("Tidak ada siswa ditemukan untuk dipindahkan.");
  }

  // 2. Batch Update: Pindahkan hak asuh siswa ke Guru Baru
  studentSnap.docs.forEach((docSnap) => {
    const studentRef = doc(db, 'siswa', docSnap.id);
    batch.update(studentRef, {
      teacherId: newTeacherId,
      updatedAt: serverTimestamp()
    });
  });

  // 3. Catat Histori Pergantian (Audit Log)
  const historyRef = doc(collection(db, 'halaqah_teacher_history'));
  const historyData: HalaqahTeacherHistory = {
    className,
    previousTeacherId: oldTeacherId,
    previousTeacherName: oldTeacherName,
    newTeacherId,
    newTeacherName,
    changedBy: coordinatorId,
    timestamp: new Date().toISOString()
  };
  batch.set(historyRef, historyData);

  // 4. Commit Transaksi
  await batch.commit();

  return `Berhasil memindahkan ${studentSnap.size} siswa dari ${oldTeacherName} ke ${newTeacherName}.`;
};

export const saveSDQReport = async (reportData: Omit<Report, 'id' | 'createdAt'>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");

  // 1. Sanitasi ID agar Deterministik (Idempotent Key)
  const safeYear = (reportData.academicYear || '2025-2026').replace(/[\/\s]/g, '');
  const safePeriod = reportData.month.trim().replace(/\s/g, '_');
  const safeType = reportData.type === 'Laporan Semester' ? 'smt' : 'bln';

  // Format ID: studentId_20252026_Desember_bln
  const deterministicId = `${reportData.studentId}_${safeYear}_${safePeriod}_${safeType}`;
  const reportRef = doc(db, 'laporan', deterministicId);

  // 2. Hitung Period Code on saving time
  const pCode = generatePeriodCode(reportData.academicYear || '', reportData.month, reportData.type);

  // 3. Simpan dengan setDoc (Overwrite aman)
  await setDoc(reportRef, {
    ...reportData,
    id: deterministicId,
    periodCode: pCode,
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp()
  });

  // 4. Sinkronisasi ke Master Siswa (Attendance, Behavior, Progress)
  try {
    const studentRef = doc(db, 'siswa', reportData.studentId);
    const updates: any = {};

    // Update Kehadiran & Adab
    if (reportData.attendance !== undefined) updates.attendance = reportData.attendance;
    if (reportData.behaviorScore !== undefined) updates.behaviorScore = reportData.behaviorScore;

    // Update Current Progress (Sabaq)
    // Prioritas: Tahfizh > Tilawah > Jangan update jika kosong
    const progressRaw = reportData.tahfizh?.individual;
    const tilawahRaw = reportData.tilawah?.individual;

    if (progressRaw && progressRaw !== '-' && progressRaw.trim().length > 3) {
      updates.currentProgress = progressRaw;
    } else if (tilawahRaw && tilawahRaw !== '-' && tilawahRaw.trim().length > 3) {
      updates.currentProgress = tilawahRaw;
    }

    if (Object.keys(updates).length > 0) {
      await updateDoc(studentRef, {
        ...updates,
        updatedAt: serverTimestamp()
      });
    }
  } catch (error) {
    console.error("Gagal sinkronisasi data siswa dari laporan:", error);
  }

  // 5. Trigger Recalculate (Total Hafalan)
  await recalculateTotalHafalan(reportData.studentId);
};

export const getReportsByTeacher = async (teacherId: string): Promise<Report[]> => {
  if (!db) return [];

  const q = query(
    collection(db, 'laporan'), 
    where('teacherId', '==', teacherId)
  );

  const snapshot = await getDocs(q);

  // Normalize & Sort di Client Side untuk menjamin urutan campuran data lama/baru
  const reports = snapshot.docs.map(doc => normalizeReportData(doc.id, doc.data()));

  return reports.sort((a, b) => {
    // Priority Sort: Period Code Descending
    const codeA = a.periodCode || 0;
    const codeB = b.periodCode || 0;
    if (codeA !== codeB) return codeB - codeA;
    // Fallback Sort: CreatedAt
    return b.createdAt.localeCompare(a.createdAt);
  });
};

export const subscribeToReportsByTeacher = (teacherId: string, onUpdate: (reports: Report[]) => void): Unsubscribe => {
  if (!db) return () => {};
  const q = query(
    collection(db, 'laporan'), 
    where('teacherId', '==', teacherId)
  );

  return onSnapshot(q, (snapshot) => {
    const reports = snapshot.docs.map(doc => normalizeReportData(doc.id, doc.data()));

    const sortedReports = reports.sort((a, b) => {
        const codeA = a.periodCode || 0;
        const codeB = b.periodCode || 0;
        if (codeA !== codeB) return codeB - codeA;
        return b.createdAt.localeCompare(a.createdAt);
    });

    onUpdate(sortedReports);
  });
};

