              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

payload.text:
Tentu, ini adalah tugas krusial untuk menjaga integritas data Anda. Sebagai pakar Firestore, saya telah menyusun skrip migrasi yang aman, menggunakan fitur **Write Batch** agar proses penulisan dan penghapusan terjadi secara atomik (efisien dan cepat).

Skrip ini akan memproses dokumen secara bertahap (batch per 500 dokumen sesuai limit Firestore) untuk mencegah *timeout* atau kegagalan transaksi.

Berikut adalah kode JavaScript yang bisa Anda buatkan filenya (misal: `services/migrationService.ts` atau jalankan di satu komponen Admin):

```javascript
import { 
  collection, 
  getDocs, 
  writeBatch, 
  doc 
} from 'firebase/firestore';
import { db } from '../lib/firebase'; // Pastikan path ke config firebase Anda benar

/**
 * SKRIP MIGRASI ID LAPORAN
 * Aturan ID: [TIPE]_[TAHUN]_[PERIODE]_[NAMA_SISWA]_[ID_UNIK]
 */
export const migrateReportIDs = async () => {
  if (!db) {
    console.error("Firestore belum terinisialisasi.");
    return;
  }

  console.log("🚀 Memulai Migrasi ID Laporan...");

  try {
    const laporanRef = collection(db, 'laporan');
    const snapshot = await getDocs(laporanRef);

    if (snapshot.empty) {
      console.log("ℹ️ Tidak ada data laporan yang ditemukan.");
      return;
    }

    let batch = writeBatch(db);
    let count = 0;
    let successCount = 0;

    for (const docSnap of snapshot.docs) {
      const data = docSnap.data();
      const oldId = docSnap.id;

      // --- LOGIKA GENERASI ID BARU ---

      // 1. [TIPE]
      const tipe = data.type === "Laporan Bulanan" ? "BLN" : "SMT";

      // 2. [TAHUN] (2025/2026 -> 2526)
      let tahun = "0000";
      if (data.academicYear) {
        const years = data.academicYear.split(/[\/-]/);
        if (years.length >= 2) {
          tahun = years[0].trim().slice(-2) + years[1].trim().slice(-2);
        }
      }

      // 3. [PERIODE] (Month atau Semester)
      const periode = (data.month || data.semester || "UKWN").toUpperCase().trim();

      // 4. [NAMA_SISWA] (Kata pertama, Uppercase, Buang karakter non-huruf)
      let nama = "SISWA";
      if (data.studentName) {
        nama = data.studentName.trim().split(' ')[0].replace(/[^a-zA-Z]/g, '').toUpperCase();
      }

      // 5. [ID_UNIK] (5 digit awal studentId)
      const unik = (data.studentId || "XXXXX").substring(0, 5).toUpperCase();

      // GABUNGKAN ID
      const newId = `${tipe}_${tahun}_${periode}_${nama}_${unik}`;

      // CEK APAKAH ID SUDAH BERUBAH? 
      // Jika ID saat ini sudah sama dengan pola baru (misal hasil migrasi sebelumnya), kita skip.
      if (oldId === newId) {
        continue;
      }

      // --- PROSES BATCH ---

      const oldDocRef = doc(db, 'laporan', oldId);
      const newDocRef = doc(db, 'laporan', newId);

      // Set data ke ID baru (gunakan { ...data } untuk memastikan semua field terbawa)
      batch.set(newDocRef, { ...data, id: newId });

      // Hapus dokumen dengan ID lama
      batch.delete(oldDocRef);

      count++;
      successCount++;

      // Limit Batch Firestore adalah 500 operasi
      if (count >= 400) {
        await batch.commit();
        batch = writeBatch(db);
        count = 0;
        console.log(`⏳ Sedang memproses... ${successCount} data termigrasi.`);
      }
    }

    // Commit sisa data
    if (count > 0) {
      await batch.commit();
    }

    console.log(`✅ Migrasi Selesai! Total ${successCount} dokumen diperbarui.`);
    return `Berhasil merapikan ${successCount} ID Laporan.`;

  } catch (error) {
    console.error("❌ Terjadi kesalahan saat migrasi:", error);
    throw error;
  }
};
```

### Cara Menjalankan di React:

Anda bisa memanggil fungsi di atas melalui sebuah tombol di halaman dashboard Koordinator:

```tsx
import { migrateReportIDs } from './services/migrationService';

// Di dalam komponen:
const handleMigration = async () => {
  if (window.confirm("Apakah Anda yakin ingin merapikan semua ID Laporan? Tindakan ini tidak bisa dibatalkan.")) {
    try {
      const result = await migrateReportIDs();
      alert(result);
    } catch (e) {
      alert("Gagal melakukan migrasi. Cek konsol.");
    }
  }
};

<button onClick={handleMigration} className="bg-red-600 text-white p-2 rounded">
  Jalankan Pembersihan ID Database
</button>
```

### Catatan Keamanan Penting:

1.  **Backup Data**: Sangat disarankan untuk melakukan **Export Data** melalui Firebase Console sebelum menjalankan skrip ini, untuk berjaga-jaga jika ada pola nama yang tidak terduga.
2.  **Relasi Data**: Jika ada koleksi lain (misal: koleksi `notifikasi` atau `log`) yang menyimpan referensi ke `doc.id` dari koleksi laporan, Anda juga perlu mengupdate referensi di koleksi tersebut. Jika koleksi laporan hanya berdiri sendiri, skrip ini sangat aman.
3.  **Idempotent**: Skrip ini bersifat aman jika dijalankan berkali-kali (`oldId === newId` akan di-skip), sehingga tidak akan terjadi duplikasi data jika proses terputus di tengah jalan.

